//! Cross-check `f_mft.parquet` vs reference `f_mft_reference.csv`.
//!
//! This implements the offline comparison described in
//! `docs/MFT_INVESTIGATION_F_DRIVE.md` §11.3:
//!
//! - Load the reference CSV generated by `vendor/mft-reader-rs`.
//! - Load the Parquet produced by `uffs-mft`.
//! - Join on FRS / record number.
//! - Compare `is_directory` / `is_base_record` vs reference `IsDirectory` /
//!   `IsBaseRecord`.
//! - Print high-level agreement stats and focused info for high-impact "missing
//!   parents" FRS.
//!
//! Usage (typical):
//!
//! ```bash
//! cargo run -p uffs-diag --release --bin cross-check-mft-reference -- \
//!   docs/trial_runs/UltraFastFileSearch/f_mft_reference.csv \
//!   docs/trial_runs/UltraFastFileSearch/f_mft.parquet
//! ```

#![expect(
    unused_crate_dependencies,
    reason = "shared Cargo.toml dependencies not used by all binaries"
)]
#![expect(
    clippy::print_stdout,
    clippy::print_stderr,
    reason = "diagnostic tool — stdout/stderr output is intentional"
)]

use std::env;
use std::path::Path;

use anyhow::{Context as _, Result};
use uffs_polars::{
    BooleanChunked, CsvParseOptions, CsvReadOptions, DataFrame, DataFrameJoinOps as _, DataType,
    JoinArgs, JoinType, SerReader as _,
};

fn main() -> Result<()> {
    let args: Vec<String> = env::args().collect();
    if args.len() != 3 {
        let program = args
            .first()
            .map_or("cross-check-mft-reference", String::as_str);
        eprintln!("Usage: {program} <f_mft_reference.csv> <f_mft.parquet>");
        std::process::exit(1);
    }

    let csv_path = args.get(1).map_or_else(
        || {
            eprintln!("Missing <f_mft_reference.csv> argument");
            std::process::exit(1);
        },
        Path::new,
    );
    let parquet_path = args.get(2).map_or_else(
        || {
            eprintln!("Missing <f_mft.parquet> argument");
            std::process::exit(1);
        },
        Path::new,
    );

    println!("{}", "=".repeat(70));
    println!("MFT Reference vs Parquet Cross-Check");
    println!("{}", "=".repeat(70));
    println!("Reference CSV : {}", csv_path.display());
    println!("Parquet       : {}", parquet_path.display());

    let df_ref = load_reference_csv(csv_path)?;
    let df_parquet = load_parquet(parquet_path)?;

    println!("\nReference rows: {}", df_ref.height());
    println!("Parquet rows  : {}", df_parquet.height());

    let joined = join_on_frs(&df_ref, &df_parquet)?;
    println!("Joined rows   : {}", joined.height());

    summarize_directory_agreement(&joined)?;

    // Hard-code the high-impact missing parents from §10.1 so we can
    // immediately inspect them once the reference CSV is present.
    let focus_frs = [2_640_657_u64, 2_631_176, 2_628_892, 2_628_924, 2_627_024];

    // 1) Look at any joined rows (where both reference and Parquet have a record
    //    for the FRS).
    print_focus_frs(&joined, &focus_frs)?;

    // 2) Additionally, inspect reference-only parents and all of their children in
    //    the Parquet file. This is crucial for understanding high-impact missing
    //    parents where the parent FRS never appears as a row in `f_mft.parquet`,
    //    but is heavily referenced by children.
    print_reference_and_children(&df_ref, &df_parquet, &focus_frs)?;

    Ok(())
}

/// Load the reference CSV produced by the legacy reader into a `DataFrame`.
#[expect(
    clippy::single_call_fn,
    reason = "encapsulates CSV loading with focused error context"
)]
fn load_reference_csv(path: &Path) -> Result<DataFrame> {
    // The reference writer always emits a header row with well-known column
    // names (RecordNumber, IsDirectory, IsBaseRecord, ...).
    let options = CsvReadOptions::default()
        .with_has_header(true)
        .with_parse_options(
            CsvParseOptions::default()
                .with_separator(b',')
                .with_quote_char(Some(b'"')),
        );

    let df = options
        .try_into_reader_with_file_path(Some(path.into()))?
        .finish()
        .with_context(|| format!("Failed to read reference CSV from {}", path.display()))?;

    Ok(df)
}

/// Load the Rust-generated Parquet export of the raw MFT into a `DataFrame`.
#[expect(
    clippy::single_call_fn,
    reason = "encapsulates Parquet loading with focused error context"
)]
fn load_parquet(path: &Path) -> Result<DataFrame> {
    let file = std::fs::File::open(path)
        .with_context(|| format!("Failed to open Parquet file: {}", path.display()))?;

    uffs_polars::ParquetReader::new(file)
        .finish()
        .with_context(|| format!("Failed to read Parquet data from {}", path.display()))
}

/// Join the reference and Parquet `DataFrame`s on FRS / record number.
#[expect(
    clippy::single_call_fn,
    reason = "encapsulates join logic with key normalization"
)]
fn join_on_frs(df_ref: &DataFrame, df_parquet: &DataFrame) -> Result<DataFrame> {
    // Normalize key columns:
    // - reference: RecordNumber (u64)
    // - parquet  : frs (u64)

    let mut df_ref_owned = df_ref.clone();
    if !df_ref_owned
        .get_column_names()
        .iter()
        .any(|name| *name == "RecordNumber")
    {
        anyhow::bail!("Reference CSV is missing required RecordNumber column");
    }

    let mut df_parquet_owned = df_parquet.clone();
    if !df_parquet_owned
        .get_column_names()
        .iter()
        .any(|name| *name == "frs")
    {
        anyhow::bail!("Parquet file is missing required frs column");
    }

    // Ensure both keys are UInt64.
    df_ref_owned
        .with_column(
            df_ref_owned
                .column("RecordNumber")?
                .cast(&DataType::UInt64)?,
        )
        .context("Failed to cast RecordNumber to UInt64")?;

    df_parquet_owned
        .with_column(df_parquet_owned.column("frs")?.cast(&DataType::UInt64)?)
        .context("Failed to cast frs to UInt64")?;

    let df_ref_key = df_ref_owned.rename("RecordNumber", "frs".into())?;

    let joined = df_ref_key
        .join(
            df_parquet,
            ["frs"],
            ["frs"],
            JoinArgs::new(JoinType::Inner),
            None,
        )
        .context("Failed to join reference CSV and Parquet on frs/RecordNumber")?;

    Ok(joined)
}

/// Print summary statistics about directory/base-record agreement between
/// the reference CSV and the Parquet `DataFrame`.
fn summarize_directory_agreement(df: &DataFrame) -> Result<()> {
    println!("\nDirectory/base-record agreement summary:");

    // Reference booleans
    let is_dir_ref_series = df.column("IsDirectory")?.cast(&DataType::Boolean)?;
    let is_dir_ref = is_dir_ref_series
        .bool()
        .context("IsDirectory column is not boolean-compatible")?;

    let is_base_ref_series = df.column("IsBaseRecord")?.cast(&DataType::Boolean)?;
    let is_base_ref = is_base_ref_series
        .bool()
        .context("IsBaseRecord column is not boolean-compatible")?;

    // Parquet booleans
    let is_dir_parquet_series = df.column("is_directory")?.cast(&DataType::Boolean)?;
    let is_dir_parquet = is_dir_parquet_series
        .bool()
        .context("is_directory column is not boolean-compatible")?;

    // We currently do not have an explicit is_base_record flag in the Parquet
    // schema; approximate using the absence of a non-zero base_file_record_segment
    // column where present.
    let has_base_segment_col = df
        .get_column_names()
        .iter()
        .any(|name| *name == "base_file_record_segment");

    let is_base_parquet_opt: Option<BooleanChunked> = if has_base_segment_col {
        let base_seg_series = df
            .column("base_file_record_segment")?
            .cast(&DataType::UInt64)?;

        let base_seg = base_seg_series
            .u64()
            .context("base_file_record_segment is not UInt64-compatible")?;

        let bools: BooleanChunked = base_seg
            .iter()
            .map(|opt_v| opt_v == Some(0))
            .collect::<BooleanChunked>()
            .with_name("is_base_record_parquet".into());

        Some(bools)
    } else {
        None
    };

    let len = df.height();
    let mut total = 0_u64;
    let mut dir_match = 0_u64;
    let mut dir_mismatch = 0_u64;
    let mut base_match = 0_u64;
    let mut base_mismatch = 0_u64;

    for idx in 0..len {
        let r_dir = is_dir_ref.get(idx).unwrap_or(false);
        let p_dir = is_dir_parquet.get(idx).unwrap_or(false);

        let r_base = is_base_ref.get(idx).unwrap_or(false);
        let p_base = is_base_parquet_opt
            .as_ref()
            .and_then(|chunked: &BooleanChunked| chunked.get(idx))
            .unwrap_or(false);

        total += 1;

        if r_dir == p_dir {
            dir_match += 1;
        } else {
            dir_mismatch += 1;
        }

        if has_base_segment_col {
            if r_base == p_base {
                base_match += 1;
            } else {
                base_mismatch += 1;
            }
        }
    }

    println!("Total joined rows     : {total}");
    println!("Directory flag matches: {dir_match}");
    println!("Directory mismatches  : {dir_mismatch}");

    if has_base_segment_col {
        println!("Base-record matches   : {base_match}");
        println!("Base-record mismatches: {base_mismatch}");
    } else {
        println!("Base-record comparison: skipped (no base_file_record_segment column)");
    }

    Ok(())
}

/// Print detailed joined rows for a set of FRS of special interest.
#[expect(
    clippy::single_call_fn,
    reason = "encapsulates focused FRS inspection for readability"
)]
fn print_focus_frs(df: &DataFrame, frs_values: &[u64]) -> Result<()> {
    println!("\nFocused inspection for high-impact missing parents:");

    for &target in frs_values {
        println!("\n--- FRS {target} ---");

        // Build a boolean mask over rows where frs == target.
        let frs_col = df
            .column("frs")?
            .u64()
            .context("Column 'frs' is not UInt64")?;

        let mask: BooleanChunked = frs_col
            .iter()
            .map(|opt_v| opt_v.map(|value| value == target))
            .collect();

        let filtered = df
            .filter(&mask)
            .with_context(|| format!("Failed to filter for FRS {target}"))?;

        if filtered.height() == 0 {
            println!("(no joined row for this FRS)");
            continue;
        }

        // Print a small subset of relevant columns if present.
        let cols_to_show = [
            "frs",
            "IsDirectory",
            "IsBaseRecord",
            "is_directory",
            "base_file_record_segment",
            "name",
            "file_name",
            "ParentRecordNumber",
            "parent_frs",
        ];

        let available: Vec<_> = cols_to_show
            .iter()
            .copied()
            .filter(|candidate| {
                filtered
                    .get_column_names()
                    .iter()
                    .any(|name| name == candidate)
            })
            .collect();

        let subset = filtered.select(&available)?;
        println!("{subset}");
    }

    Ok(())
}

/// For a set of FRS values, print:
///
/// - The reference-side rows (from the vendored CSV) for those FRS, even when
///   they are *not* present in the joined `DataFrame`; and
/// - All children in the Parquet `DataFrame` that reference those FRS via
///   `parent_frs`.
///
/// This is designed to answer two key questions for high-impact missing
/// parents:
///
/// 1. Does the reference reader believe this FRS is an in-use directory?
/// 2. How many children in our Rust pipeline treat this FRS as their parent,
///    even when we never emit a corresponding directory row?
#[expect(
    clippy::single_call_fn,
    reason = "encapsulates reference-vs-children analysis for readability"
)]
fn print_reference_and_children(
    df_ref: &DataFrame,
    df_parquet: &DataFrame,
    frs_values: &[u64],
) -> Result<()> {
    println!("\nReference-only parents and children in Parquet:");

    for &target in frs_values {
        println!("\n=== FRS {target} ===");

        // Reference side: filter by RecordNumber == target.
        let ref_filtered = filter_by_u64_eq(df_ref, "RecordNumber", target)
            .with_context(|| format!("Failed to filter reference for RecordNumber {target}"))?;

        if ref_filtered.height() == 0 {
            println!("Reference: (no record with RecordNumber = {target})");
        } else {
            println!("Reference:");

            // Show a compact subset of the most relevant columns if present.
            let cols_to_show_ref = [
                "RecordNumber",
                "SequenceNumber",
                "InUse",
                "IsDirectory",
                "IsBaseRecord",
                "ParentRecordNumber",
                "ParentSequenceNumber",
                "FileName",
                "LinkCount",
            ];

            let available_ref: Vec<_> = cols_to_show_ref
                .iter()
                .copied()
                .filter(|candidate| {
                    ref_filtered
                        .get_column_names()
                        .iter()
                        .any(|name| name == candidate)
                })
                .collect();

            let subset_ref = ref_filtered.select(&available_ref)?;
            println!("{subset_ref}");
        }

        // Children in Parquet: filter by parent_frs == target.
        let children = filter_by_u64_eq(df_parquet, "parent_frs", target).with_context(|| {
            format!("Failed to filter Parquet children for parent_frs {target}")
        })?;

        if children.height() == 0 {
            println!("Children in Parquet: (no rows with parent_frs = {target})");
        } else {
            println!("Children in Parquet (parent_frs = {target}):");

            let cols_to_show_children = ["frs", "parent_frs", "is_directory", "name", "file_name"];

            let available_children: Vec<_> = cols_to_show_children
                .iter()
                .copied()
                .filter(|candidate| {
                    children
                        .get_column_names()
                        .iter()
                        .any(|name| name == candidate)
                })
                .collect();

            let subset_children = children.select(&available_children)?;
            println!("{subset_children}");
        }
    }

    Ok(())
}

/// Helper: build a boolean mask for `column == target` (after casting the
/// column to `UInt64`) and return the filtered `DataFrame`.
fn filter_by_u64_eq(df: &DataFrame, column: &str, target: u64) -> Result<DataFrame> {
    let series = df
        .column(column)
        .with_context(|| format!("Missing required column '{column}'"))?
        .cast(&DataType::UInt64)
        .with_context(|| format!("Column '{column}' is not UInt64-compatible"))?;

    let values = series
        .u64()
        .context("Failed to obtain UInt64 view after cast")?;

    let mask: BooleanChunked = values
        .iter()
        .map(|opt_v| opt_v.map(|value| value == target))
        .collect();

    let filtered = df
        .filter(&mask)
        .with_context(|| format!("Failed to filter on {column} == {target}"))?;

    Ok(filtered)
}
